import zlib, re

with open\('11_-_ShotMarker_Manual_Apr2020.pdf', 'rb'\) as f:
    data = f.read\(\)

# Find all streams and try to extract readable text
all_text = []
for match in re.finditer\(rb'stream\\r?\\n\(.+?\)\\r?\\nendstream', data, re.DOTALL\):
    raw = match.group\(1\)
    try:
        decompressed = zlib.decompress\(raw\)
        # Look for BT...ET text blocks
        for bt_match in re.finditer\(rb'BT\(.+?\)ET', decompressed, re.DOTALL\):
            block = bt_match.group\(1\)
            # Extract Tj and TJ text
            for tj in re.findall\(rb'\\\(\([^\)]*\)\\\)\\s*Tj', block\):
                try:
                    text = tj.decode\('latin-1', errors='ignore'\).strip\(\)
                    if text:
                        all_text.append\(text\)
                except:
                    pass
            # TJ arrays
            for tj_array in re.findall\(rb'\\[\([^\\]]+\)\\]\\s*TJ', block\):
                parts = re.findall\(rb'\\\(\([^\)]*\)\\\)', tj_array\)
                line = ''
                for p in parts:
                    try:
                        line += p.decode\('latin-1', errors='ignore'\)
                    except:
                        pass
                if line.strip\(\):
                    all_text.append\(line.strip\(\)\)
    except:
        pass

# Print all extracted text
for i, t in enumerate\(all_text\):
    print\(f'{i}: {t}'\)
